void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv += uTexSize.zw/2;
vec2 uv1 = vUv-.5;
uv2 = vec2(1/vRadius,vAngle)*.2;
vec2 uv_echo = (vUv - 0.5)*vec2(-1,-1) + 0.5;
float k1 = .2;

uv2 = fract((vUv-.5)*k1+.5);
uv3 = fract((uv_echo-.5)*k1+.5);
vec3 ret0 = GetBlur3(uv2)+GetBlur3(uv3) ;
float dx = lum(GetPixel(vUv-uTexSize.zw)) - lum(GetPixel(vUv+uTexSize.zw));
      dx += lum(GetPixel(uv_echo-uTexSize.zw)) - lum(GetPixel(uv_echo+uTexSize.zw));


    ret = mix( texture(sampler_main, vUv).xyz,
                texture(sampler_main, uv_echo).xyz,
                0.50);

    ret = max( texture(sampler_main, vUv).xyz,
                texture(sampler_main, uv_echo).xyz)/1.5;


    ret = 2*max(GetBlur3(vUv),GetBlur3(uv_echo)) + ret*3;;

